#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Pinpoint + clear the root lock-holder gridlocking enrichment (exit-0-safe). Uses
pg_blocking_pids() to find the query everything waits on, greps the worker for runtime
ALTER TABLE (the suspected recurring-DDL cause), and terminates the root blockers."""
import os,sys,json,time,subprocess
def sh(c,t=20):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "ERR"
def psql(q,t=18):
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc",q],capture_output=True,text=True,timeout=t)
    return (r.stdout.strip() if r.returncode==0 else "ERR")
out={"kind":"lockfix","ts":int(time.time())}
try:
    # the root blockers: PIDs that block the most other backends
    out["blocker_chain"]=psql("""SELECT blocking_pid||' blocks '||cnt||' | '||state||' '||round(age_s)||'s | '||substr(q,1,70) FROM (
      SELECT bl.pid AS blocking_pid, count(*) cnt, max(a.state) state, max(extract(epoch from now()-a.query_start)) age_s, max(a.query) q
      FROM pg_stat_activity w
      JOIN LATERAL unnest(pg_blocking_pids(w.pid)) AS bl(pid) ON true
      JOIN pg_stat_activity a ON a.pid=bl.pid
      GROUP BY bl.pid ORDER BY cnt DESC LIMIT 5) s""")
    out["waiting_on_lock"]=psql("SELECT count(*) FROM pg_stat_activity WHERE wait_event_type='Lock'")
    out["active"]=psql("SELECT count(*) FROM pg_stat_activity WHERE state='active'")
    # grep worker + related for runtime ALTER
    out["worker_alter"]=sh("grep -rnE 'ALTER TABLE|ADD COLUMN' /opt/atlas/enrich/*.py /opt/atlas/importers/atlas_enrich*.py 2>/dev/null | head -12")
    # KILL the root blockers (anything blocking others AND running/idle-in-txn > 30s)
    out["killed_blockers"]=psql("""SELECT count(*) FROM (SELECT pg_terminate_backend(pid) FROM (
        SELECT DISTINCT bl.pid FROM pg_stat_activity w
        JOIN LATERAL unnest(pg_blocking_pids(w.pid)) AS bl(pid) ON true
        JOIN pg_stat_activity a ON a.pid=bl.pid
        WHERE now()-a.state_change > interval '30 seconds') z) y""")
    out["killed_ddl"]=psql("SELECT count(*) FROM (SELECT pg_terminate_backend(pid) FROM pg_stat_activity WHERE query ILIKE 'ALTER TABLE%' AND state='active') x")
    time.sleep(8)
    out["active_after"]=psql("SELECT count(*) FROM pg_stat_activity WHERE state='active'")
    out["total_after"]=psql("SELECT count(*)||'/'||current_setting('max_connections') FROM pg_stat_activity")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/lockfix.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"lockfix","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
